import torch
import torch.nn as nn
from torch.utils.cpp_extension import load_inline

# Define the robust CUDA kernel for parallel prefix sum
scan_source = """
#include <torch/extension.h>
#include <cuda_runtime.h>
#include <cassert>

template<typename T>
__device__ __forceinline__ T safe_load(const T* arr, int idx, int n) {
    return (idx >= 0 && idx < n) ? arr[idx] : T(0);
}

template<typename T>
__device__ __forceinline__ void safe_store(T* arr, int idx, int n, T value) {
    if (idx >= 0 && idx < n) arr[idx] = value;
}

template<typename T>
__global__ void row_scan_kernel(const T* input, T* output, int rows, int cols) {
    int row = blockIdx.x;
    int tid = threadIdx.x;

    if (row >= rows) return;

    extern __shared__ T shared[];

    // Load row into shared memory with bounds checking
    for (int i = tid; i < cols; i += blockDim.x) {
        shared[i] = input[row * cols + i];
    }
    __syncthreads();

    // Robust Blelloch parallel scan adapted for arbitrary sizes
    // Up-sweep phase
    int offset = 1;
    for (int d = cols >> 1; d > 0; d >>= 1) {
        __syncthreads();
        if (tid < d) {
            int ai = offset * (2 * tid + 1) - 1;
            int bi = offset * (2 * tid + 2) - 1;
            if (bi < cols) {
                shared[bi] += shared[ai];
            }
        }
        offset <<= 1;
    }

    // Down-sweep phase
    if (tid == 0) {
        if (cols > 0) {
            shared[cols - 1] = T(0);
        }
    }

    for (int d = 1; d < cols; d <<= 1) {
        offset >>= 1;
        __syncthreads();

        if (tid < d) {
            int ai = offset * (2 * tid + 1) - 1;
            int bi = offset * (2 * tid + 2) - 1;
            if (bi < cols && ai < cols) {
                T t = shared[ai];
                shared[ai] = shared[bi];
                shared[bi] += t;
            }
        }
    }

    __syncthreads();

    // Store results with bounds checking
    for (int i = tid; i < cols; i += blockDim.x) {
        output[row * cols + i] = shared[i];
    }
}

torch::Tensor parallel_scan_cuda(torch::Tensor x, int dim) {
    // Validate input
    TORCH_CHECK(x.is_cuda(), "Input tensor must be on GPU");
    TORCH_CHECK(x.is_contiguous(), "Input tensor must be contiguous");

    auto sizes = x.sizes();
    int n = sizes[dim];
    TORCH_CHECK(n > 0, "Scan dimension must have positive size");

    int total_elements = x.numel();
    int outer_elements = total_elements / n;

    // Reshape to 2D
    auto x_reshaped = x.reshape({outer_elements, n}).contiguous();
    auto out = torch::zeros_like(x_reshaped);

    auto x_ptr = x_reshaped.data_ptr<float>();
    auto out_ptr = out.data_ptr<float>();

    // Configure kernel - use enough threads but not more than cols
    int threads = min(256, ((n + 31) / 32) * 32);  // Round up to nearest 32
    threads = max(threads, 32);  // At least 1 warp
    int shared_mem_size = n * sizeof(float);

    // Validate shared memory size doesn't exceed device limits
    int max_shared_mem;
    cudaDeviceGetAttribute(&max_shared_mem, cudaDevAttrMaxSharedMemoryPerBlock, 0);
    TORCH_CHECK(shared_mem_size <= max_shared_mem, 
                "Required shared memory exceeds device limit");

    row_scan_kernel<float><<<outer_elements, threads, shared_mem_size>>>(
        x_ptr, out_ptr, outer_elements, n
    );

    C10_CUDA_KERNEL_LAUNCH_CHECK();

    return out.reshape(sizes);
}
"""

scan_cpp_source = """
torch::Tensor parallel_scan_cuda(torch::Tensor x, int dim);
"""

# Compile the inline CUDA code
scan_module = load_inline(
    name="parallel_scan",
    cpp_sources=scan_cpp_source,
    cuda_sources=scan_source,
    functions=["parallel_scan_cuda"],
    verbose=False,
    with_cuda=True,
    extra_cuda_cflags=["-O3"],
)


class ModelNew(nn.Module):
    """
    Optimized model that performs cumulative sum using robust CUDA kernels.
    """

    def __init__(self, dim):
        super(ModelNew, self).__init__()
        self.dim = dim
        self.scan_module = scan_module

    def forward(self, x):
        return self.scan_module.parallel_scan_cuda(x, self.dim)
